#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vUv-= 0.5;
    vUv.y*=-1;
    vUv *= uAspect.xy;

    float rotspeed = 0.02*q5 + uTime*0.2;
    vUv = vec2(cos(rotspeed)*vUv.x - sin(rotspeed)*vUv.y, sin(rotspeed)*vUv.x + cos(rotspeed)*vUv.y);

    float beat = q32;

    ret = texture( sampler_main, vUv ).xyz;

    vec3 col = 0;

    vec3 lookat = vec3(3*sin(0.2*uTime), 3*cos(q5*0.05), 0);

    float zoom = 0.15;

    vec3 ro = vec3(0, 0, -1);

    vec3 F = normalize(lookat-ro); // Forward
    vec3 R = normalize(cross(vec3(0., 1., 0.), F)); //Right
    vec3 U = cross(F, R); //Up

    vec3 C = ro + F*zoom;
    vec3 I = C + vUv.x*R + vUv.y*U;
    vec3 rd = normalize(I-ro);
    float t = uTime;

    float dS, dO;
    vec3 p;
    float breakloop = 0;
    for(int i = 0; i<100 && breakloop == 0; i++)
    {
        p = ro + rd * dO;
        dS = -(length(vec2(length(p.xz)-1, p.y)) -0.75);
        if(dS < 0.001) {breakloop = 1; }
        dO += dS;
    }
    float check1 = q8;
    float check2 = q9;
    float check3 = q10;
    if(dS < 0.003)
    {
        float x = atan(p.x,p.z) - rotspeed;
        float y = atan(length(p.xz)-1, p.y);
        float bands = sin(y*100 + x*3);
        float ripples = sin((x*10 - y*30)*3)*0.5 + 0.5;
        float waves = tan(x*4 - y*2 + q5*0.4);
        float b1 = smoothstep(-0.2, 0.2, bands);
        float b2 = smoothstep(-0.2, 0.2, bands-0.5);
        float m = b1*(1-b2);
        m = max(m,ripples*b2*max(30,waves));
        m += max(0,waves*0.2*b2);
        float m2 = m-ripples-waves;
        float m22 = 0.5*m2 + m2*q3*1.5;
        float m3 = b1*waves;
        if(check1 == 1) {col = 0.4*vec3(m22,m22, m22);}
        if(check2 == 1) {col = vec3(m22*0.5,0, 0);}
        if(check3 == 1) {col = vec3(m22*0.2,0, m22*0.5);}
        col += vec3(0.2*m3 + m3*q2, 0*m3*q3*0.5, 0);
        //col = waves;

    }

    ret = col*2;

    // darken (decay) over uTime
    ret *= 0.317; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uvb = (vUv-0.5)*0.9+0.5;
float tilt = 0.5*sin(uTime*.03);
uvb = (vUv-0.5)*0.9+0.5;
uv2 = 1.9*(vUv-0.5) / (2+(vUv.y-0.5)*tilt);

chan = floor(num/2+uv2.x*num);
sig  = GetBlur1(vec2(0.99,chan/num)).r/uAspect.y;
sig2 = GetBlur1(vec2(0.99,chan/num)).g/uAspect.y;
sig3 = GetBlur2(vec2(0.99,chan/num)).r*1/uAspect.y;
sig4 = GetBlur3(vec2(0.99,uv2.x+0.5)).r*2/uAspect.y;

targ = 6.28*(uv2.x*num)-0.5;
tube0 = sat(0.25-0.75*cos(targ));
tube  = tube0* sat (200*sig-abs(500*(-uv2.y +0.002*tube0*sign(uv2.y))));
tube  = tube*0.25+exp(-4*abs(tube-0.3))*(tube>0);

//dots = pow(tube0,2)* exp(abs(200*sig2-abs(500*(-uv2.y+tube0*.01*sign(uv2.y)))));
dots = pow(tube0,2)* 2/abs(200*sig2-abs(500*(-uv2.y+tube0*.004*sign(uv2.y))));

//dots = pow(tube0,2)* (abs(200*sig2-abs(500*(-uv2.y+tube0*.004*sign(uv2.y))))<3);
dotmask = dots>.2;
uvb += -.05*sin(uTime+targ ) * ((tube>0)||dotmask) ;
col0 = scol(vUv.x+uTime/12);
col =  col0* sat(sig3*16-0.5);
col2 = (col0+0.5)* sat(sig4*16-0.5);

float cld = texture(sampler_noise_hq,vUv/8+uTime*0.002).r;
back = 0.2*cld*vec3 (0,0.6,1);
back *= GP(uvb).b;
back += GP(uvb).r/2;
back += GP(uvb).r*(0.5+col)*(sig4*3*vUv.y);
back *= 1.25;
//back *= sat (1-2*GP(uvb).g); //dark stars

back += exp(-12*length(uvb.y-0.5+(GP(uvb).b-0.5)*.6*rand_preset*vRadius))*col2*0.5*sqrt(audioMidSmooth);

ret = back + (dots + tube/2)*col;
ret += !tube * exp(-3/sig/tube0*abs(uv2.y))*(col+0.5)*sig;

ret += .1*dotmask*(1-dots/4);//*GetBlur1(uvb).r*41;

//ret = GetPixel(vUv);

  fragColor = ret;
}
